    if (efd < 0) {
        perror("Failed to create eventfd");
        close(src_fd);
        close(dst_fd);
        return EXIT_FAILURE;
    }

    // FIOCLONE_ASYNC 호출
    if (ioctl(dst_fd, FIOCLONE_ASYNC, src_fd) < 0) {
        perror("FIOCLONE_ASYNC ioctl failed");
        close(src_fd);
        close(dst_fd);
        close(efd);
