sendTrackPriority(dataChannel, "videoTrack1", "medium");
```

#### Receiving and Handling Priority Updates

```javascript
// Assume dataChannel is an established RTCDataChannel
dataChannel.onmessage = function(event) {
    const message = JSON.parse(event.data);

    if (message.type === "TRACK_PRIORITY") {
        const trackId = message.trackId;
        const priority = message.priority;

        // Handle the priority update
        updateTrackPriority(trackId, priority);
    }
};

function updateTrackPriority(trackId, priority) {
