    // Example: Adjust bandwidth allocation or quality settings
}
```

### Implementation Notes

- **Track Identification**: Ensure that each track has a unique identifier that both peers understand.
- **Priority Handling**: Define how your application will adjust track handling based on the priority. This could involve changing bandwidth allocation, adjusting encoding parameters, or other application-specific logic.
- **Synchronization**: Ensure that both peers have a consistent understanding of track identifiers and priority levels.

This approach allows you to implement a custom priority signaling mechanism over a WebRTC data channel, with the application layer responsible for interpreting and acting on these signals.

"TRACK_PRIORITY" 메시지 형식은 WebRTC 표준에 정의되어 있지 않기 때문에, 이를 구현하려면 애플리케이션 레벨에서 커스텀 메시지 형식을 설계해야 합니다. 아래는 JSON 형식으로 "TRACK_PRIORITY" 메시지를 정의하고, 이를 통해 오디오 및 비디오 트랙의 우선순위를 업데이트하는 의사코드 예시입니다.

### TRACK_PRIORITY 메시지 형식 (JSON)

```json
{
  "type": "TRACK_PRIORITY",
  "tracks": [
    {
      "trackId": "audioTrack1",
      "priority": "high"
    },
    {
      "trackId": "videoTrack1",
      "priority": "medium"
    }
  ]
}
```

### 필드 정의

- `type`: 메시지의 유형을 나타내며, 여기서는 "TRACK_PRIORITY"로 설정합니다.
- `tracks`: 우선순위를 설정할 트랙의 배열입니다.
  - `trackId`: 각 트랙의 고유 식별자입니다. 이는 `MediaStreamTrack.id`와 같은 값을 사용할 수 있습니다.
  - `priority`: 트랙의 우선순위 수준을 나타냅니다. 예를 들어, "high", "medium", "low"와 같은 문자열로 정의할 수 있습니다.

### 의사코드 예시

#### 송신 측 (Sender)

```javascript
// 데이터 채널을 통해 TRACK_PRIORITY 메시지 전송
function sendTrackPriority(dataChannel, trackPriorities) {
  const message = {
    type: "TRACK_PRIORITY",
    tracks: trackPriorities
  };
  dataChannel.send(JSON.stringify(message));
}

// 예시: 오디오 및 비디오 트랙의 우선순위 설정
const trackPriorities = [
  { trackId: "audioTrack1", priority: "high" },
  { trackId: "videoTrack1", priority: "medium" }
];

sendTrackPriority(dataChannel, trackPriorities);
```

#### 수신 측 (Receiver)

```javascript
// 데이터 채널에서 메시지 수신 및 처리
dataChannel.onmessage = function(event) {
  const message = JSON.parse(event.data);

  if (message.type === "TRACK_PRIORITY") {
    updateTrackPriorities(message.tracks);
  }
};

// 트랙 우선순위 업데이트 함수
function updateTrackPriorities(tracks) {
  tracks.forEach(trackInfo => {
    const track = getTrackById(trackInfo.trackId);
    if (track) {
      // 우선순위에 따라 트랙의 전송 매개변수 조정
      const sender = peerConnection.getSenders().find(s => s.track === track);
      if (sender) {
        const parameters = sender.getParameters();
        // 예시: 우선순위에 따라 대역폭 조정
        if (trackInfo.priority === "high") {
          parameters.encodings[0].maxBitrate = 500000; // 500 kbps
        } else if (trackInfo.priority === "medium") {
          parameters.encodings[0].maxBitrate = 300000; // 300 kbps
        } else {
          parameters.encodings[0].maxBitrate = 100000; // 100 kbps
        }
        sender.setParameters(parameters);
      }
    }
  });
}

// 트랙 ID로 트랙 찾기 (예시 함수)
function getTrackById(trackId) {
  // 구현에 따라 트랙을 찾는 로직을 작성
  return localStream.getTracks().find(track => track.id === trackId);
}
```

